CODE_EXAMPLE:
interface Shape { double area(); }

class Circle    implements Shape { double r; public double area() { return Math.PI * r * r; } }
class Rectangle implements Shape { double w, h; public double area() { return w * h; } }
// Adding Triangle requires no change to existing classes
class Triangle  implements Shape { double b, h; public double area() { return 0.5 * b * h; } }

class AreaCalculator {
    double totalArea(List<Shape> shapes) {
        return shapes.stream().mapToDouble(Shape::area).sum();
    }
}

UNIT_TEST_EXAMPLE:
@Test
public void totalArea_sumsAllShapes() {
    List<Shape> shapes = List.of(new Circle(1.0), new Rectangle(2.0, 3.0));
    AreaCalculator calc = new AreaCalculator();
    assertEquals(Math.PI + 6.0, calc.totalArea(shapes), 0.001);
}

@Test
public void totalArea_worksWithNewShapeWithoutModification() {
    List<Shape> shapes = List.of(new Triangle(4.0, 3.0));
    assertEquals(6.0, new AreaCalculator().totalArea(shapes), 0.001);
}
